final class Order {
    private final String customerId;
    private final List<String> items;
    private final String shippingAddress;
    private final String paymentMethod;
    private final String couponCode;
    private final boolean giftWrap;
    private final String giftMessage;
    private final boolean insurance;
    private final String deliveryNotes;
    private final double total;

    private Order(Builder b) {
        this.customerId = b.customerId;
        this.items = List.copyOf(b.items);
        this.shippingAddress = b.shippingAddress;
        this.paymentMethod = b.paymentMethod;
        this.couponCode = b.couponCode;
        this.giftWrap = b.giftWrap;
        this.giftMessage = b.giftMessage;
        this.insurance = b.insurance;
        this.deliveryNotes = b.deliveryNotes;
        this.total = b.total;
    }

    public static class Builder {
        private String customerId;
        private List<String> items;
        private String shippingAddress;
        private String paymentMethod;
        private String couponCode;
        private boolean giftWrap;
        private String giftMessage;
        private boolean insurance;
        private String deliveryNotes;
        private double total;

        public Builder customerId(String id) { this.customerId = id; return this; }
        public Builder items(List<String> i) { this.items = i; return this; }
        public Builder shippingAddress(String a) { this.shippingAddress = a; return this; }
        public Builder paymentMethod(String p) { this.paymentMethod = p; return this; }
        public Builder couponCode(String c) { this.couponCode = c; return this; }
        public Builder giftWrap(boolean g) { this.giftWrap = g; return this; }
        public Builder giftMessage(String m) { this.giftMessage = m; return this; }
        public Builder insurance(boolean i) { this.insurance = i; return this; }
        public Builder deliveryNotes(String n) { this.deliveryNotes = n; return this; }
        public Builder total(double t) { this.total = t; return this; }

        public Order build() {
            if (customerId == null) throw new IllegalStateException("Customer ID required");
            if (items == null || items.isEmpty()) throw new IllegalStateException("Items required");
            if (shippingAddress == null) throw new IllegalStateException("Address required");
            if (giftMessage != null && !giftWrap)
                throw new IllegalStateException("Gift message requires gift wrap");
            return new Order(this);
        }
    }
}

