class Notification {
    private final String title;
    private final String body;
    private final List<String> tags;  // is this truly immutable?
    private String priority;          // wait... not final?

    Notification(Builder b) {         // not private!
        this.title = b.title;
        this.body = b.body;
        this.tags = b.tags;           // shared reference!
        this.priority = b.priority;
    }

    public void setPriority(String p) { this.priority = p; }  // setter!
    public List<String> getTags() { return tags; }             // mutable list!

    static class Builder {
        String title, body, priority;
        List<String> tags = new ArrayList<>();
        Builder title(String t) { title = t; return this; }
        Builder body(String b) { body = b; return this; }
        Builder priority(String p) { priority = p; return this; }
        Builder addTag(String t) { tags.add(t); return this; }
        Notification build() { return new Notification(this); }
    }
}

