final class Notification {
    private final String title;
    private final String body;
    private final List<String> tags;
    private final String priority;           // FIX 1: make final

    private Notification(Builder b) {        // FIX 2: make private
        this.title = b.title;
        this.body = b.body;
        this.tags = List.copyOf(b.tags);     // FIX 3: defensive copy
        this.priority = b.priority;
    }

    // FIX 4: remove setter
    // public void setPriority -- DELETED

    public String getTitle() { return title; }
    public String getBody() { return body; }
    public List<String> getTags() { return tags; }  // already immutable from List.copyOf
    public String getPriority() { return priority; }

    static class Builder {
        private String title, body, priority;
        private final List<String> tags = new ArrayList<>();
        Builder title(String t) { title = t; return this; }
        Builder body(String b) { body = b; return this; }
        Builder priority(String p) { priority = p; return this; }
        Builder addTag(String t) { tags.add(t); return this; }
        Notification build() {
            if (title == null) throw new IllegalStateException("Title required");
            return new Notification(this);
        }
    }
}

challenges.starterCode:
// DESIGN THIS: Factory + Builder composition
// Requirements:
// - Push: supports title, body, image, action buttons (max 3), priority
// - Email: supports title, body (HTML), CC, BCC, attachments
// - SMS: supports body only (max 160 chars), no title, no image
//
// Factory picks the right builder based on channel.
// Each builder validates its channel's constraints.
// Built Notification is immutable.
//
// Usage should look like:
// Notification n = NotificationFactory.createBuilder("push")
//     .title("Order Shipped")
//     .body("Your laptop is on the way")
//     .image("laptop.png")
//     .build();

challenges.solutionCode:
interface NotificationBuilder {
    NotificationBuilder title(String t);
    NotificationBuilder body(String b);
    Notification build();
}

class PushBuilder implements NotificationBuilder {
    private String title, body, image;
    private List<String> buttons = new ArrayList<>();
    private String priority = "normal";

    public PushBuilder title(String t) { this.title = t; return this; }
    public PushBuilder body(String b) { this.body = b; return this; }
    public PushBuilder image(String i) { this.image = i; return this; }
    public PushBuilder addButton(String btn) { buttons.add(btn); return this; }
    public PushBuilder priority(String p) { this.priority = p; return this; }

    public Notification build() {
        if (title == null) throw new IllegalStateException("Push needs title");
        if (body == null) throw new IllegalStateException("Push needs body");
        if (buttons.size() > 3) throw new IllegalStateException("Max 3 buttons");
        return new Notification("push", title, body, image, List.copyOf(buttons), priority);
    }
}

class SmsBuilder implements NotificationBuilder {
    private String body;

    public SmsBuilder title(String t) {
        // SMS doesn't support title -- ignore or warn
        return this;
    }
    public SmsBuilder body(String b) { this.body = b; return this; }

    public Notification build() {
        if (body == null) throw new IllegalStateException("SMS needs body");
        if (body.length() > 160) throw new IllegalStateException("SMS max 160 chars");
        return new Notification("sms", null, body, null, List.of(), "normal");
    }
}

class NotificationFactory {
    static NotificationBuilder createBuilder(String channel) {
        return switch(channel.toLowerCase()) {
            case "push" -> new PushBuilder();
            case "sms" -> new SmsBuilder();
            default -> throw new IllegalArgumentException("Unknown: " + channel);
        };
    }
}
